    /**
     * FR-003 Requirement: System MUST maintain existing email categories
     *
     * This test validates that all 6 core categories are defined in the configuration.
     * The test maps FR-003 category names to their actual configuration keys:
     * - "receipts" → financial category (with receipt-related rules)
     * - "shipping notifications" → household category (with shipping-related rules)
     * - "newsletters" → (validated through domain sources and rules)
     * - "action items" → (validated through actionable attribute and rules)
     * - "financial statements" → financial category (with statement-related rules)
     * - "family communications" → (validated through personal attribute and rules)
     */
    test('should have financial category for receipts and financial statements', () => {
      // Validate financial category exists
      expect(config.categorySignals).toHaveProperty('financial');

      const financial = config.categorySignals.financial;

      // Validate required fields
      expect(financial).toHaveProperty('hardAssertions');
      expect(financial).toHaveProperty('strongIndicators');
      expect(financial).toHaveProperty('rules');
      expect(financial).toHaveProperty('description');

      // Validate description mentions receipts and statements
      expect(financial.description).toBeDefined();
    });

