      // Validate household category exists
      expect(config.categorySignals).toHaveProperty('household');

      const household = config.categorySignals.household;

      // Validate required fields
      expect(household).toHaveProperty('hardAssertions');
      expect(household).toHaveProperty('strongIndicators');
      expect(household).toHaveProperty('rules');
      expect(household).toHaveProperty('description');
    });

